mapper.select:
SELECT ir.id, ir.production_line_id, ir.route_code, ir.route_name, ir.creator_id, ir.created_at AS createdAt, ir.updated_at AS updatedAt FROM inspection_route ir WHERE ir.production_line_id = #{productionLineId}
AND ir.creator_id = #{creatorId}
ORDER BY ir.id DESC

mapper.update:
UPDATE inspection_route
production_line_id = #{productionLineId}, route_code = #{routeCode}, route_name = #{routeName}, updated_at = #{updatedAt},
WHERE id = #{id}

mapper.select:
SELECT ir.id, ir.production_line_id, ir.route_code, ir.route_name, ir.creator_id, ir.created_at AS createdAt, ir.updated_at AS updatedAt, pl.line_name AS productionLineName, su.real_name AS creatorName, su.username AS creatorUsername FROM inspection_route ir LEFT JOIN production_line pl ON ir.production_line_id = pl.id LEFT JOIN sys_user su ON ir.creator_id = su.id
AND ir.creator_id = #{creatorId}
AND ir.production_line_id = #{productionLineId}
AND ir.route_code LIKE CONCAT('%', #{routeCode}, '%')
AND ir.route_name LIKE CONCAT('%', #{routeName}, '%')
ORDER BY ir.id DESC

SELECT id, production_line_id, route_code, route_name, creator_id, created_at AS createdAt, updated_at AS updatedAt FROM inspection_route
AND creator_id = #{creatorId}
AND production_line_id = #{productionLineId}
AND route_code = #{routeCode}

